```
'use strict'

function compose(middleware) {
  return function (context, next) {
    let index = -1
    return dispatch(0)
    function dispatch(i) {
      if (i <= index) return Promise.reject(new Error('next() called multiple times'))
      index = i
      let fn = middleware[i]
      if (!fn) return Promise.resolve()
      try {
        return Promise.resolve(fn(context, function next () {
          return dispatch(i + 1)
        }))
      } catch (err) {
        return Promise.reject(err)
      }
    }
  }
}

const getTestMiddWare = (loggerA, loggerB) => async (ctx, next) => {
  console.log(loggerA);
  await next();
  console.log(loggerB);
};

const mid1 = getTestMiddWare(1, 4);
const mid2 = getTestMiddWare(2, 3);
const mid3 = async (context, next) => {
  const data = await new Promise((resolve, reject) => {
    setTimeout(() => resolve('数据已经取出'), 1000);
  });
  await next();
  console.log(data);  
};

const middlewares = [];
middlewares.push(mid1, mid2, mid3);

const context = {};
compose(middlewares)(context);
```

